import React from 'react';
import { ImageGallery } from './ImageGallery';
import './styles.css';

const images = Array.from({ length: 12 }, (_, i) => ({
  id: i,
  url: `https://picsum.photos/seed/${i + 1}/400/300`,
  alt: `Photo ${i + 1}`,
}));

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '28rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Image Gallery</h1>
      <ImageGallery images={images} />
    </div>
  );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import './styles.css';

interface ImageData {
  id: number;
  url: string;
  alt: string;
}

interface ImageGalleryProps {
  images: ImageData[];
}

// TODO: Implement lazy loading with IntersectionObserver
// Currently all images load immediately — fix this

export const ImageGallery: React.FC<ImageGalleryProps> = ({ images }) => {
  const [loadedCount, setLoadedCount] = useState(0);

  return (
    <div>
      <p data-testid="loaded-count" className="gallery__count">
        {loadedCount} of {images.length} loaded
      </p>
      <div className="gallery">
        {images.map((image, index) => (
          <div
            key={image.id}
            data-testid={`img-container-${index}`}
            className="gallery__item"
          >
            {/* TODO: Add skeleton placeholder */}
            <div data-testid={`skeleton-${index}`} className="gallery__skeleton" />

            {/* BUG: Image loads immediately — should lazy load */}
            <img
              data-testid={`img-${index}`}
              src={image.url}
              alt={image.alt}
              className="gallery__img"
              onLoad={() => setLoadedCount(c => c + 1)}
            />
          </div>
        ))}
      </div>
    </div>
  );
};

.gallery__count {
  font-size: 0.8125rem;
  color: #6b7280;
  margin-bottom: 0.75rem;
}

.gallery {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.gallery__item {
  position: relative;
  border-radius: 0.5rem;
  overflow: hidden;
  aspect-ratio: 4 / 3;
  background: #f3f4f6;
}

.gallery__skeleton {
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, #f3f4f6 25%, #e5e7eb 50%, #f3f4f6 75%);
  background-size: 200% 100%;
  animation: skeleton-shimmer 1.5s ease-in-out infinite;
}

.gallery__skeleton--hidden {
  display: none;
}

@keyframes skeleton-shimmer {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

.gallery__img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  opacity: 0;
  transition: opacity 0.3s ease;
}

.gallery__img--loaded {
  opacity: 1;
}

