import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

// Mock IntersectionObserver
let observerCallback: IntersectionObserverCallback;
let observedElements: Element[] = [];

const mockIntersectionObserver = jest.fn((cb: IntersectionObserverCallback) => {
  observerCallback = cb;
  return {
    observe: jest.fn((el: Element) => { observedElements.push(el); }),
    unobserve: jest.fn(),
    disconnect: jest.fn(),
  };
});

window.IntersectionObserver = mockIntersectionObserver as any;

function simulateIntersect(elements: Element[]) {
  const entries = elements.map(el => ({
    target: el,
    isIntersecting: true,
    intersectionRatio: 1,
    boundingClientRect: {} as DOMRectReadOnly,
    intersectionRect: {} as DOMRectReadOnly,
    rootBounds: null,
    time: Date.now(),
  }));
  observerCallback(entries, {} as IntersectionObserver);
}

describe('Lazy Loading Images', () => {
  beforeEach(() => {
    observedElements = [];
  });

  it('renders image containers', () => {
    render(<App />);
    expect(screen.getByTestId('img-container-0')).toBeInTheDocument();
    expect(screen.getByTestId('img-container-11')).toBeInTheDocument();
  });

  it('images do not have src initially', () => {
    render(<App />);
    const img = screen.getByTestId('img-0');
    // src should not be the actual URL (should be empty or data-src)
    expect(img.getAttribute('src') || '').not.toContain('picsum');
  });

  it('creates IntersectionObserver', () => {
    render(<App />);
    expect(mockIntersectionObserver).toHaveBeenCalled();
  });

  it('skeletons are visible initially', () => {
    render(<App />);
    expect(screen.getByTestId('skeleton-0')).toBeInTheDocument();
  });

  it('displays loaded count', () => {
    render(<App />);
    expect(screen.getByTestId('loaded-count')).toHaveTextContent('0 of 12 loaded');
  });

  it('observes image elements', () => {
    render(<App />);
    expect(observedElements.length).toBeGreaterThan(0);
  });
});

