import React, { useState, useEffect, useRef, useCallback } from 'react';
import './styles.css';

interface ImageData {
  id: number;
  url: string;
  alt: string;
}

interface ImageGalleryProps {
  images: ImageData[];
}

export const ImageGallery: React.FC<ImageGalleryProps> = ({ images }) => {
  const [loadedCount, setLoadedCount] = useState(0);
  const [visibleSet, setVisibleSet] = useState<Set<number>>(new Set());
  const [loadedSet, setLoadedSet] = useState<Set<number>>(new Set());
  const imgRefs = useRef<(HTMLImageElement | null)[]>([]);
  const observerRef = useRef<IntersectionObserver | null>(null);

  useEffect(() => {
    observerRef.current = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            const idx = imgRefs.current.indexOf(entry.target as HTMLImageElement);
            if (idx !== -1) {
              setVisibleSet(prev => new Set(prev).add(idx));
              observerRef.current?.unobserve(entry.target);
            }
          }
        });
      },
      { rootMargin: '200px' }
    );

    imgRefs.current.forEach(el => {
      if (el) observerRef.current?.observe(el);
    });

    return () => {
      observerRef.current?.disconnect();
    };
  }, [images]);

  const handleLoad = useCallback((index: number) => {
    setLoadedSet(prev => new Set(prev).add(index));
    setLoadedCount(c => c + 1);
  }, []);

  return (
    <div>
      <p data-testid="loaded-count" className="gallery__count">
        {loadedCount} of {images.length} loaded
      </p>
      <div className="gallery">
        {images.map((image, index) => (
          <div
            key={image.id}
            data-testid={`img-container-${index}`}
            className="gallery__item"
          >
            {!loadedSet.has(index) && (
              <div data-testid={`skeleton-${index}`} className="gallery__skeleton" />
            )}

            <img
              ref={el => { imgRefs.current[index] = el; }}
              data-testid={`img-${index}`}
              src={visibleSet.has(index) ? image.url : undefined}
              alt={image.alt}
              loading="lazy"
              className={`gallery__img${loadedSet.has(index) ? ' gallery__img--loaded' : ''}`}
              onLoad={() => handleLoad(index)}
            />
          </div>
        ))}
      </div>
    </div>
  );
};
